// // This module selects the second input data line (i_dat1) when the control signal is LOW and the first input data line (i_dat0) when the control signal is HIGH.
module top_module(input		[31:0]	i_dat0, i_dat1, 
		 input			control,
		 output	reg	[31:0]	o_dat);always @(*) 
		if (!control)
			o_dat = i_dat0;
		else
			o_dat = i_dat1;	

endmodule
